          let status = 'draft';
          let color = 'default';
          
          if (availableFrom && availableTo) {
            if (now.isBefore(availableFrom)) {
              status = 'scheduled';
              color = 'orange';
            } else if (now.isAfter(availableTo)) {
              status = 'expired';
              color = 'red';
            } else {
              status = 'active';
              color = 'green';
