  // Render Listening Exercises
  const renderListeningExercises = () => {
    const exerciseColumns = [
      {
        title: 'Exercise',
        key: 'exercise',
        render: (_, record) => (
          <Space>
            <AudioOutlined style={{ fontSize: 20, color: '#1890ff' }} />
            <div>
              <Text strong>{record.title}</Text>
              <br />
              <Text type="secondary" style={{ fontSize: '12px' }}>
                {record.description}
              </Text>
            </div>
          </Space>
        )
      },
      {
        title: 'Course',
        dataIndex: 'course',
        key: 'course',
        render: (course) => {
          const courseData = courses.find(c => c._id === course);
          return <Tag color="blue">{courseData?.title || 'Unknown'}</Tag>;
        }
      },
      {
        title: 'Level',
        dataIndex: 'level',
        key: 'level',
        render: (level) => {
          const colors = {
            beginner: 'green',
            intermediate: 'orange',
            advanced: 'red'
          };
          return <Tag color={colors[level]}>{level?.toUpperCase()}</Tag>;
        }
      },
      {
        title: 'Duration',
        dataIndex: 'duration',
        key: 'duration',
        render: (duration) => `${duration || 0} sec`
      },
      {
        title: 'Questions',
        dataIndex: 'questions',
        key: 'questions',
        render: (questions) => (
          <Badge count={questions?.length || 0} showZero>
            <QuestionCircleOutlined style={{ fontSize: 20 }} />
          </Badge>
        )
      },
      {
        title: 'Play Limit',
        dataIndex: 'playLimit',
        key: 'playLimit',
        render: (limit) => <Tag>{limit || 3} plays</Tag>
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Tooltip title={playingExerciseId === record._id && isPlaying ? "Pause Audio" : "Play Audio"}>
              <Button
                icon={playingExerciseId === record._id && isPlaying ? 
                  <PauseCircleOutlined /> : <PlayCircleOutlined />}
                size="small"
                type={playingExerciseId === record._id ? "primary" : "default"}
                onClick={async () => {
                  if (playingExerciseId === record._id && isPlaying) {
                    // Pause current audio
                    if (tableAudioRef.current) {
                      tableAudioRef.current.pause();
                    }
                    setIsPlaying(false);
                    setPlayingExerciseId(null);
                  } else {
                    // Check authentication status first
                    const token = localStorage.getItem('token') || localStorage.getItem('authToken');
                    if (!token) {
                      message.error({
                        content: 'Please log in to play audio files. Redirecting to login...',
                        duration: 3
                      });
                      setTimeout(() => {
                        localStorage.clear();
                        window.location.href = '/login';
                      }, 3000);
                      return;
                    }

                    try {
                      // Stop any currently playing audio
                      if (tableAudioRef.current) {
                        tableAudioRef.current.pause();
                        tableAudioRef.current.currentTime = 0;
                      }
                      
                      // Create audio element for this exercise
                      if (record.audioUrl) {
                        console.log('Creating audio element for:', record.title, 'URL:', record.audioUrl);
                        
                        const audio = new Audio();
                        tableAudioRef.current = audio;
                        
                        // Remove crossOrigin to avoid CORS preflight issues with Azure
                        // audio.crossOrigin = 'anonymous';
                        
                        audio.onloadstart = () => {
                          console.log('Audio loading started for:', record.title);
                        };
                        
                        audio.onloadeddata = () => {
                          console.log('Audio data loaded for:', record.title);
                        };
                        
                        audio.oncanplay = () => {
                          console.log('Audio can play for:', record.title);
                        };
                        
                        audio.oncanplaythrough = () => {
                          console.log('Audio can play through for:', record.title);
                        };
                        
                        audio.onloadedmetadata = () => {
                          setDuration(audio.duration);
                          console.log('Audio metadata loaded, duration:', audio.duration, 'seconds');
                        };
                        
                        audio.ontimeupdate = () => {
                          setCurrentTime(audio.currentTime);
                        };
                        
                        audio.onended = () => {
                          setIsPlaying(false);
                          setPlayingExerciseId(null);
                          setCurrentTime(0);
                          console.log('Audio playback ended');
                        };
                        
                        audio.onerror = (error) => {
                          console.error('Audio error event:', error);
                          console.error('Audio error details:', {
                            error: audio.error,
                            networkState: audio.networkState,
                            readyState: audio.readyState,
                            src: audio.src
                          });
                          
                          let errorMessage = 'Unknown audio error';
                          if (audio.error) {
                            switch(audio.error.code) {
                              case audio.error.MEDIA_ERR_ABORTED:
                                errorMessage = 'Audio playback was aborted';
                                break;
                              case audio.error.MEDIA_ERR_NETWORK:
                                errorMessage = 'Network error while loading audio';
                                break;
                              case audio.error.MEDIA_ERR_DECODE:
                                errorMessage = 'Audio file is corrupted or invalid format';
                                break;
                              case audio.error.MEDIA_ERR_SRC_NOT_SUPPORTED:
                                errorMessage = 'Audio format not supported by browser';
                                break;
                              default:
                                errorMessage = `Audio error code: ${audio.error.code}`;
                            }
                          }
                          
                          console.error('Failed to play audio:', errorMessage);
                          message.error(`Failed to play audio: ${errorMessage}`);
                          setIsPlaying(false);
                          setPlayingExerciseId(null);
                        };
                        
                        // Enhanced loading with fallback approach
                        const attemptAudioLoad = async () => {
                          try {
                            // Get authentication token for Azure requests
                            const token = localStorage.getItem('token');
                            
                            // Set the source with authentication if needed
                            audio.src = record.audioUrl;
                            
                            // Wait for metadata to load
                            await new Promise((resolve, reject) => {
                              const loadTimeout = setTimeout(() => {
                                reject(new Error('Audio loading timeout'));
                              }, 10000); // 10 second timeout
                              
                              audio.onloadedmetadata = () => {
                                clearTimeout(loadTimeout);
                                resolve();
                              };
                              
                              audio.onerror = () => {
                                clearTimeout(loadTimeout);
                                reject(new Error('Failed to load audio metadata'));
                              };
                              
                              audio.load();
                            });
                            
                            // Try to play
                            console.log('Attempting to play audio for:', record.title);
                            await audio.play();
                            setIsPlaying(true);
                            setPlayingExerciseId(record._id);
                            console.log('Audio playback started successfully');
                            
                          } catch (loadError) {
                            console.error('Audio load/play error:', loadError);
                            
                            // Try alternative approach with authenticated fetch and blob
                            try {
                              console.log('Trying authenticated blob approach for Azure backend...');
                              
                              // Check if user is authenticated
                              const token = localStorage.getItem('token') || localStorage.getItem('authToken');
                              if (!token) {
                                throw new Error('No authentication token found. Please log in again.');
                              }
                              
                              // Use the helper function to fetch authenticated audio
                              const blobUrl = await fetchAuthenticatedAudio(record.audioUrl);
                              audio.src = blobUrl;
                              
                              await new Promise((resolve, reject) => {
                                const loadTimeout = setTimeout(() => {
                                  reject(new Error('Blob audio loading timeout'));
                                }, 10000); // Increase timeout for Azure
                                
                                audio.onloadedmetadata = () => {
                                  clearTimeout(loadTimeout);
                                  console.log('Authenticated audio metadata loaded, duration:', audio.duration);
                                  setDuration(audio.duration);
                                  resolve();
                                };
                                
                                audio.onerror = () => {
                                  clearTimeout(loadTimeout);
                                  reject(new Error('Failed to load authenticated blob audio'));
                                };
                                
                                audio.load();
                              });
                              
                              await audio.play();
                              setIsPlaying(true);
                              setPlayingExerciseId(record._id);
                              console.log('Authenticated Azure audio playback started successfully');
                              
                              // Cleanup blob URL after playback ends
                              audio.onended = () => {
                                setIsPlaying(false);
                                setPlayingExerciseId(null);
                                setCurrentTime(0);
                                URL.revokeObjectURL(blobUrl);
                                console.log('Audio playback ended, blob URL cleaned up');
                              };
                              
                            } catch (blobError) {
                              console.error('Authenticated blob approach failed:', blobError);
                              
                              // Provide specific error messages based on the error type
                              if (blobError.message.includes('401') || blobError.message.includes('Unauthorized')) {
                                message.error({
                                  content: 'Audio access requires authentication. Please refresh the page and try again.',
                                  duration: 6
                                });
                              } else if (blobError.message.includes('No authentication token')) {
                                message.error({
                                  content: 'Please log in again to access audio files.',
                                  duration: 6
                                });
                              } else if (blobError.message.includes('Network Error') || blobError.message.includes('timeout')) {
                                message.error({
                                  content: 'Network error loading audio. Please check your connection and try again.',
                                  duration: 6
                                });
                              } else {
                                message.error({
                                  content: `Audio playback error: ${blobError.message}`,
                                  duration: 6
                                });
                              }
                              setIsPlaying(false);
                              setPlayingExerciseId(null);
                            }
                          }
                        };
                        
                        await attemptAudioLoad();
                      } else {
                        console.warn('No audio URL for exercise:', record.title);
                        message.warning('No audio file available for this exercise');
                      }
                    } catch (error) {
                      console.error('Error playing audio:', error);
                      message.error('Failed to play audio file');
                      setIsPlaying(false);
                      setPlayingExerciseId(null);
                    }
                  }
                }}
                loading={playingExerciseId === record._id && !isPlaying && !tableAudioRef.current}
              />
            </Tooltip>
            {playingExerciseId === record._id && isPlaying && (
              <div style={{ minWidth: 100 }}>
                <Text type="secondary" style={{ fontSize: 12 }}>
                  {Math.floor(currentTime / 60)}:{(currentTime % 60).toFixed(0).padStart(2, '0')} / 
                  {Math.floor(duration / 60)}:{(duration % 60).toFixed(0).padStart(2, '0')}
                </Text>
              </div>
            )}
            <Tooltip title="Edit">
              <Button
                icon={<EditOutlined />}
                size="small"
                onClick={() => {
                  // Stop any playing audio when editing
                  if (tableAudioRef.current) {
                    tableAudioRef.current.pause();
                    tableAudioRef.current.currentTime = 0;
                  }
                  setIsPlaying(false);
                  setPlayingExerciseId(null);
                  
                  console.log('Editing exercise:', record);
                  setEditingExercise(record);
                  setQuestions(record.questions || []);
                  exerciseForm.setFieldsValue(record);
                  setExerciseModalVisible(true);
                  console.log('Exercise modal opened for editing');
                }}
              />
            </Tooltip>
            <Tooltip title="View Submissions">
              <Button
                icon={<EyeOutlined />}
                size="small"
                onClick={() => {
                  setSelectedExercise(record);
                  setSubmissionsModalVisible(true);
                }}
              />
            </Tooltip>
            <Popconfirm
              title="Are you sure you want to delete this exercise?"
              onConfirm={async () => {
                try {
                  // Stop any playing audio before deleting
                  if (tableAudioRef.current && playingExerciseId === record._id) {
                    tableAudioRef.current.pause();
                    setIsPlaying(false);
                    setPlayingExerciseId(null);
                  }
                  
                  const response = await fetch(`${API_BASE_URL}/api/listening-exercises/${record._id}`, {
                    method: 'DELETE',
                    headers: getAuthHeaders()
                  });
                  if (response.ok) {
                    message.success('Exercise deleted successfully');
                    fetchListeningExercises();
                  } else {
                    throw new Error('Failed to delete exercise');
                  }
                } catch (error) {
                  console.error('Error deleting exercise:', error);
                  message.error('Failed to delete exercise');
                }
              }}
            >
              <Tooltip title="Delete">
                <Button icon={<DeleteOutlined />} size="small" danger />
              </Tooltip>
            </Popconfirm>
          </Space>
        )
      }
    ];

    return (
      <div>
        <Title level={2}>🎧 Listening Exercises</Title>
        <Text type="secondary">Create and manage listening comprehension exercises</Text>

        <Row gutter={[16, 16]} style={{ marginTop: 24, marginBottom: 24 }}>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Exercises"
                value={listeningExercises.length}
                prefix={<AudioOutlined />}
                valueStyle={{ color: '#1890ff' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Beginner Level"
                value={listeningExercises.filter(e => e.level === 'beginner').length}
                prefix={<StarOutlined />}
                valueStyle={{ color: '#52c41a' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Questions"
                value={listeningExercises.reduce((sum, e) => sum + (e.questions?.length || 0), 0)}
                prefix={<QuestionCircleOutlined />}
                valueStyle={{ color: '#faad14' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Avg. Duration"
                value={Math.round(listeningExercises.reduce((sum, e) => sum + (e.duration || 0), 0) / listeningExercises.length || 0)}
                suffix="sec"
                prefix={<ClockCircleOutlined />}
                valueStyle={{ color: '#722ed1' }}
              />
            </Card>
          </Col>
        </Row>

        <Card
          title="Listening Exercises"
          extra={
            <Space>
              <Input
                placeholder="Search exercises..."
                prefix={<SearchOutlined />}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={{ width: 200 }}
              />
              <Button
                type="primary"
                icon={<PlusOutlined />}
                onClick={() => {
                  setEditingExercise(null);
                  setQuestions([]);
                  setAudioFile(null);
                  setFileList([]);
                  exerciseForm.resetFields();
                  setExerciseModalVisible(true);
                }}
              >
                Create Exercise
              </Button>
            </Space>
          }
        >
          <Table
            columns={exerciseColumns}
            dataSource={listeningExercises.filter(exercise => {
              const matchesSearch = !searchTerm || 
                exercise.title?.toLowerCase().includes(searchTerm.toLowerCase());
              return matchesSearch;
            })}
            rowKey="_id"
            pagination={{
              pageSize: 10,
              showSizeChanger: true,
              showQuickJumper: true
            }}
          />
        </Card>
      </div>
    );
  };

  // Render Student Progress
  const renderStudentProgress = () => (
    <div>
      <Title level={2}>👥 Student Progress</Title>
      <Text type="secondary">Monitor student performance and progress across all courses</Text>

      <Row gutter={[16, 16]} style={{ marginTop: 24, marginBottom: 24 }}>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Total Students"
              value={students.length}
              prefix={<TeamOutlined />}
              valueStyle={{ color: '#1890ff' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Active Students"
              value={students.filter(s => s.isApproved === true).length}
              prefix={<CheckCircleOutlined />}
              valueStyle={{ color: '#52c41a' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Avg. Progress"
              value={75}
              suffix="%"
              prefix={<TrophyOutlined />}
              valueStyle={{ color: '#faad14' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Completion Rate"
              value={68}
              suffix="%"
              prefix={<CheckSquareOutlined />}
              valueStyle={{ color: '#722ed1' }}
            />
          </Card>
        </Col>
      </Row>

      <Card title="Student Performance Overview">
        <Table
          columns={[
            {
              title: 'Student',
              key: 'student',
              render: (_, record) => (
                <div>
                  <Text strong>{record.firstName} {record.lastName}</Text>
                  <br />
                  <Text type="secondary" style={{ fontSize: '12px' }}>
                    {record.email}
                  </Text>
                </div>
              )
            },
            {
              title: 'Enrolled Courses',
              key: 'courses',
              render: () => (
                <Badge count={Math.floor(Math.random() * 5) + 1} showZero>
                  <BookOutlined style={{ fontSize: 20 }} />
                </Badge>
              )
            },
            {
              title: 'Progress',
              key: 'progress',
              render: () => {
                const progress = Math.floor(Math.random() * 100);
                return (
                  <Progress
                    percent={progress}
                    size="small"
                    strokeColor={progress >= 70 ? '#52c41a' : progress >= 40 ? '#faad14' : '#f5222d'}
                  />
                );
              }
            },
            {
              title: 'Last Activity',
              key: 'lastActivity',
              render: () => moment().subtract(Math.floor(Math.random() * 7), 'days').format('MMM DD, YYYY')
            },
            {
              title: 'Actions',
              key: 'actions',
              render: (_, record) => (
                <Space>
                  <Button
                    icon={<EyeOutlined />}
                    size="small"
                    onClick={() => {
                      setSelectedProgress(record);
                      setProgressModalVisible(true);
                    }}
                  >
                    View Details
                  </Button>
                </Space>
              )
            }
          ]}
          dataSource={students}
          rowKey="_id"
          pagination={{
            pageSize: 10,
            showSizeChanger: true,
            showQuickJumper: true
          }}
        />
      </Card>
    </div>
  );

  // Render Analytics & Reports
  const renderAnalytics = () => (
    <div>
      <Title level={2}>📊 Analytics & Reports</Title>
      <Text type="secondary">Comprehensive analytics and reporting dashboard</Text>

      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24} lg={12}>
          <Card title="Course Enrollment Trends">
            <Bar
              data={{
                labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
                datasets: [{
                  label: 'New Enrollments',
                  data: [12, 19, 15, 25, 22, 30],
                  backgroundColor: 'rgba(24, 144, 255, 0.6)',
                  borderColor: '#1890ff',
                  borderWidth: 1
                }]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: {
                    position: 'top'
                  }
                }
              }}
            />
          </Card>
        </Col>
        
        <Col xs={24} lg={12}>
          <Card title="Student Performance Distribution">
            <Pie
              data={{
                labels: ['Excellent (90-100%)', 'Good (80-89%)', 'Average (70-79%)', 'Below Average (<70%)'],
                datasets: [{
                  data: [25, 35, 30, 10],
                  backgroundColor: [
                    '#52c41a',
                    '#1890ff',
                    '#faad14',
                    '#f5222d'
                  ]
                }]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: {
                    position: 'bottom'
                  }
                }
              }}
            />
          </Card>
        </Col>
      </Row>

      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24}>
          <Card title="Monthly Activity Report">
            <Line
              data={{
                labels: ['Week 1', 'Week 2', 'Week 3', 'Week 4'],
                datasets: [
                  {
                    label: 'Quiz Submissions',
                    data: [45, 52, 48, 61],
                    borderColor: '#1890ff',
                    backgroundColor: 'rgba(24, 144, 255, 0.1)',
                    tension: 0.4
                  },
                  {
                    label: 'Homework Submissions',
                    data: [38, 42, 35, 48],
                    borderColor: '#52c41a',
                    backgroundColor: 'rgba(82, 196, 26, 0.1)',
                    tension: 0.4
                  },
                  {
                    label: 'Material Downloads',
                    data: [65, 78, 72, 85],
                    borderColor: '#faad14',
                    backgroundColor: 'rgba(250, 173, 20, 0.1)',
                    tension: 0.4
                  }
                ]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: {
                    position: 'top'
                  }
                },
                scales: {
                  y: {
                    beginAtZero: true
                  }
                }
              }}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );

  // Render Settings
  const renderSettings = () => (
    <div>
      <Title level={2}>⚙️ System Settings</Title>
      <Text type="secondary">Configure system settings and preferences</Text>

      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24} lg={12}>
          <Card title="General Settings">
            <Form layout="vertical">
              <Form.Item label="System Name">
                <Input defaultValue="Forum Academy" />
              </Form.Item>
              <Form.Item label="Admin Email">
                <Input defaultValue="admin@forumacademy.com" />
              </Form.Item>
              <Form.Item label="Time Zone">
                <Select defaultValue="UTC">
                  <Option value="UTC">UTC</Option>
                  <Option value="EST">Eastern Time</Option>
                  <Option value="PST">Pacific Time</Option>
                  <Option value="JST">Japan Standard Time</Option>
                </Select>
              </Form.Item>
              <Form.Item label="Language">
                <Select defaultValue="en">
                  <Option value="en">English</Option>
                  <Option value="ja">Japanese</Option>
                </Select>
              </Form.Item>
            </Form>
          </Card>
        </Col>

        <Col xs={24} lg={12}>
          <Card title="Notification Settings">
            <Form layout="vertical">
              <Form.Item label="Email Notifications">
                <Switch defaultChecked />
              </Form.Item>
              <Form.Item label="SMS Notifications">
                <Switch />
              </Form.Item>
              <Form.Item label="Push Notifications">
                <Switch defaultChecked />
              </Form.Item>
              <Form.Item label="Weekly Reports">
                <Switch defaultChecked />
              </Form.Item>
            </Form>
          </Card>
        </Col>
      </Row>

      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24}>
          <Card title="System Information">
            <Descriptions bordered column={2}>
              <Descriptions.Item label="Version">v2.1.0</Descriptions.Item>
              <Descriptions.Item label="Last Updated">
                {moment().subtract(2, 'days').format('MMMM DD, YYYY')}
              </Descriptions.Item>
              <Descriptions.Item label="Database Status">
                <Tag color="green">Connected</Tag>
              </Descriptions.Item>
              <Descriptions.Item label="Server Status">
                <Tag color="green">Online</Tag>
              </Descriptions.Item>
              <Descriptions.Item label="Total Users">
                {users.length}
              </Descriptions.Item>
              <Descriptions.Item label="Total Courses">
                {courses.length}
              </Descriptions.Item>
            </Descriptions>
          </Card>
        </Col>
      </Row>
    </div>
  );

  // Render Forum Management
  // Main content renderer with integrated dashboard components
  const renderContent = () => {
    switch(activeKey) {
      case 'overview':
        return renderOverview();
      case 'applications':
        return renderApplicationsManagement();
      case 'courses':
        return renderCourseManagement();
      case 'materials':
        return renderMaterialManagement();
      case 'quizzes':
        return renderQuizManagement();
      case 'homework':
        return renderHomeworkManagement();
      case 'listening':
        return renderListeningExercises();
      case 'students':
        return renderStudentProgress();
      case 'analytics':
        return renderAnalytics();
      case 'settings':
        return renderSettings();
      default:
        return renderOverview();
    }
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
      }}>
        <Spin size="large" tip="Loading Dashboard..." />
      </div>
    );
  }

  return (
    <Layout style={{ minHeight: '100vh' }}>
      {/* Modern Sidebar */}
      <Sider 
        trigger={null} 
        collapsible 
        collapsed={collapsed}
        breakpoint="lg"
        onBreakpoint={(broken) => {
          setCollapsed(broken);
        }}
        width={260}
        className="modern-sidebar"
        style={{
          background: 'linear-gradient(180deg, #667eea 0%, #764ba2 50%, #f093fb 100%)',
          position: 'fixed',
          height: '100vh',
          left: 0,
          top: 0,
          bottom: 0,
          zIndex: 1000,
          boxShadow: '4px 0 30px rgba(102, 126, 234, 0.4)',
          overflow: 'auto'
        }}
      >
        {/* Logo Section */}
        <div className="sidebar-logo-section" style={{
          padding: '30px 20px',
          textAlign: 'center',
          borderBottom: '2px solid rgba(255, 255, 255, 0.2)',
          background: 'rgba(255, 255, 255, 0.1)'
        }}>
          <div className="logo-container">
            <div className="logo-icon-box" style={{
              width: 70,
              height: 70,
              margin: '0 auto',
              background: 'linear-gradient(135deg, #ff6b6b 0%, #ee5a52 100%)',
              borderRadius: 20,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 10px 30px rgba(255, 107, 107, 0.4)',
              marginBottom: 15
            }}>
              <RocketOutlined style={{ fontSize: 35, color: '#fff' }} />
            </div>
            {!collapsed && (
              <div>
                <Title level={3} style={{ color: '#fff', margin: 0 }}>
                  Forum Academy
                </Title>
                <Badge 
                  count="ADMIN PORTAL" 
                  style={{ 
                    backgroundColor: '#52c41a',
                    color: '#fff',
                    marginTop: 8
                  }} 
                />
              </div>
            )}
          </div>
        </div>
        
        {/* Navigation Menu */}
        <Menu
          theme="dark"
          mode="inline"
          selectedKeys={[activeKey]}
          onClick={(e) => setActiveKey(e.key)}
          style={{ 
            background: 'transparent',
            borderRight: 0,
            padding: '20px 10px'
          }}
          items={menuItems.map(item => ({
            ...item,
            style: {
              margin: '8px 0',
              borderRadius: '12px'
            }
          }))}
        />
      </Sider>

      {/* Main Layout */}
      <Layout style={{ marginLeft: collapsed ? 80 : 260, transition: 'all 0.3s' }}>
        {/* Header */}
        <Header style={{ 
          padding: '0 24px', 
          background: '#fff',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          position: 'sticky',
          top: 0,
          zIndex: 999
        }}>
          <div style={{ display: 'flex', alignItems: 'center' }}>
            <Button
              type="text"
              icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
              onClick={() => setCollapsed(!collapsed)}
              style={{
                fontSize: '16px',
                width: 64,
                height: 64,
              }}
            />
            <Breadcrumb style={{ marginLeft: 16 }}>
              <Breadcrumb.Item>
                <HomeOutlined />
              </Breadcrumb.Item>
              <Breadcrumb.Item>Dashboard</Breadcrumb.Item>
              <Breadcrumb.Item>{menuItems.find(item => item.key === activeKey)?.label}</Breadcrumb.Item>
            </Breadcrumb>
          </div>
          
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            {/* Notifications */}
            <Badge count={5}>
              <Button
                type="text"
                icon={<BellOutlined />}
                style={{ fontSize: 18 }}
              />
            </Badge>
            
            {/* User Profile Dropdown */}
            <Dropdown
              menu={{
                items: [
                  {
                    key: 'profile',
                    icon: <UserOutlined />,
                    label: 'Profile',
                    onClick: () => message.info('Profile page coming soon')
                  },
                  {
                    key: 'settings',
                    icon: <SettingOutlined />,
                    label: 'Settings',
                    onClick: () => setActiveKey('settings')
                  },
                  {
                    type: 'divider'
                  },
                  {
                    key: 'logout',
                    icon: <LogoutOutlined />,
                    label: 'Logout',
                    onClick: handleLogout
                  }
                ]
              }}
              placement="bottomRight"
            >
              <div style={{
                display: 'flex',
                alignItems: 'center',
                cursor: 'pointer',
                padding: '4px 12px',
                borderRadius: 8,
                transition: 'background 0.3s',
                maxWidth: '200px',
                '&:hover': {
                  background: '#f0f0f0'
                }
              }}>
                <Avatar
                  style={{
                    backgroundColor: '#1890ff',
                    marginRight: 8,
                    flexShrink: 0
                  }}
                  icon={<UserOutlined />}
                />
                <div style={{ minWidth: 0, flex: 1 }}>
                  <Text strong style={{
                    display: 'block',
                    whiteSpace: 'nowrap',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    fontSize: '14px'
                  }}>
                    {currentUser?.firstName} {currentUser?.lastName}
                  </Text>
                  <Text type="secondary" style={{
                    fontSize: 12,
                    display: 'block',
                    whiteSpace: 'nowrap',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis'
                  }}>
                    {currentUser?.role?.toUpperCase()}
                  </Text>
                </div>
              </div>
            </Dropdown>
          </div>
        </Header>

        {/* Content */}
        <Content style={{ 
          margin: '24px',
          minHeight: 280,
          background: '#f0f2f5'
        }}>
          {renderContent()}
        </Content>

        {/* Footer */}
        <Layout.Footer style={{ 
          textAlign: 'center',
          background: '#fff',
          borderTop: '1px solid #f0f0f0'
        }}>
          <Text type="secondary">
            Forum Academy Admin Dashboard ©{new Date().getFullYear()} | 
            <span style={{ marginLeft: 8 }}>
              Made with <HeartOutlined style={{ color: '#ff4d4f' }} /> by Forum Academy Team
            </span>
          </Text>
        </Layout.Footer>
      </Layout>

      {/* Modals */}
      
      {/* Application Details Modal */}
      <Modal
        title="Application Details"
        visible={applicationModalVisible}
        onCancel={() => setApplicationModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setApplicationModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="reply"
            icon={<MessageOutlined />}
            onClick={() => {
              setReplyType('application');
              setReplyTarget(selectedApplication);
              setApplicationModalVisible(false);
              setReplyModalVisible(true);
            }}
          >
            Reply to Applicant
          </Button>,
          selectedApplication?.status === 'pending' && (
            <>
              <Button
                key="reject"
                danger
                onClick={() => updateApplicationStatus(selectedApplication._id, 'rejected')}
              >
                Reject
              </Button>
              <Button
                key="approve"
                type="primary"
                onClick={() => updateApplicationStatus(selectedApplication._id, 'approved')}
              >
                Approve
              </Button>
            </>
          )
        ]}
      >
        {selectedApplication && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Full Name" span={2}>
              {selectedApplication.fullName}
            </Descriptions.Item>
            <Descriptions.Item label="Email">
              {selectedApplication.email}
            </Descriptions.Item>
            <Descriptions.Item label="Phone">
              {selectedApplication.phone}
            </Descriptions.Item>
            <Descriptions.Item label="Program">
              {selectedApplication.course || selectedApplication.program}
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={
                selectedApplication.status === 'pending' ? 'orange' :
                selectedApplication.status === 'approved' ? 'green' : 'red'
              }>
                {selectedApplication.status?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Applied Date">
              {moment(selectedApplication.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
            <Descriptions.Item label="Message" span={2}>
              <Paragraph ellipsis={{ rows: 3, expandable: true }}>
                {selectedApplication.message}
              </Paragraph>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* Course View Modal */}
      <Modal
        title="Course Details"
        visible={courseViewModalVisible}
        onCancel={() => setCourseViewModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setCourseViewModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="edit"
            icon={<EditOutlined />}
            onClick={() => {
              setEditingCourse(selectedCourse);
              const formValues = {
                ...selectedCourse,
                capacity: selectedCourse.maxStudents || selectedCourse.capacity || 30,
                status: selectedCourse.isActive ? 'active' : 'inactive'
              };
              
              if (selectedCourse.startDate) {
                const startDate = moment(selectedCourse.startDate);
                if (startDate.isValid()) {
                  formValues.startDate = startDate;
                }
              }
              
              if (selectedCourse.endDate) {
                const endDate = moment(selectedCourse.endDate);
                if (endDate.isValid()) {
                  formValues.endDate = endDate;
                }
              }
              
              courseForm.setFieldsValue(formValues);
              setCourseViewModalVisible(false);
              setCourseModalVisible(true);
            }}
          >
            Edit Course
          </Button>
        ]}
      >
        {selectedCourse && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Title" span={2}>
              <Text strong>{selectedCourse.title}</Text>
            </Descriptions.Item>
            <Descriptions.Item label="Code">
              <Tag color="blue">{selectedCourse.code}</Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Category">
              <Tag color="green">{selectedCourse.category}</Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Level">
              <Tag color={
                selectedCourse.level === 'beginner' ? 'green' :
                selectedCourse.level === 'intermediate' ? 'orange' : 'red'
              }>
                {selectedCourse.level?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Description" span={2}>
              <Paragraph ellipsis={{ rows: 3, expandable: true }}>
                {selectedCourse.description}
              </Paragraph>
            </Descriptions.Item>
            <Descriptions.Item label="Duration">
              {selectedCourse.duration || 12} weeks
            </Descriptions.Item>
            <Descriptions.Item label="Capacity">
              {selectedCourse.maxStudents || selectedCourse.capacity || 30} students
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={selectedCourse.isActive ? 'green' : 'default'}>
                {selectedCourse.isActive ? 'Active' : 'Inactive'}
              </Tag>
            </Descriptions.Item>
            {selectedCourse.startDate && (
              <Descriptions.Item label="Start Date">
                {moment(selectedCourse.startDate).format('MMMM DD, YYYY')}
              </Descriptions.Item>
            )}
            {selectedCourse.endDate && (
              <Descriptions.Item label="End Date">
                {moment(selectedCourse.endDate).format('MMMM DD, YYYY')}
              </Descriptions.Item>
            )}
            <Descriptions.Item label="Students Enrolled" span={2}>
              <List
                dataSource={selectedCourse.students || []}
                renderItem={(studentId) => {
                  const student = students.find(s => s._id === studentId);
                  return (
                    <List.Item>
                      <Space>
                        <Avatar icon={<UserOutlined />} size="small" />
                        <Text>{student ? `${student.firstName} ${student.lastName}` : 'Unknown'}</Text>
                      </Space>
                    </List.Item>
                  );
                }}
                size="small"
                bordered={false}
                style={{ maxHeight: 200, overflow: 'auto' }}
              />
              {(!selectedCourse.students || selectedCourse.students.length === 0) && (
                <Text type="secondary">No students enrolled yet</Text>
              )}
            </Descriptions.Item>
            <Descriptions.Item label="Created" span={2}>
              {moment(selectedCourse.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* Message Details Modal */}
      <Modal
        title="Message Details"
        visible={messageModalVisible}
        onCancel={() => setMessageModalVisible(false)}
        width={700}
        footer={[
          <Button key="close" onClick={() => setMessageModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="reply"
            type="primary"
            icon={<MailOutlined />}
            onClick={() => {
              setReplyType('message');
              setReplyTarget(selectedMessage);
              setReplyModalVisible(true);
            }}
          >
            Reply
          </Button>
        ]}
      >
        {selectedMessage && (
          <Descriptions bordered column={1}>
            <Descriptions.Item label="From">
              {selectedMessage.name} ({selectedMessage.email})
            </Descriptions.Item>
            <Descriptions.Item label="Phone">
              {selectedMessage.phone || 'Not provided'}
            </Descriptions.Item>
            <Descriptions.Item label="Subject">
              {selectedMessage.subject}
            </Descriptions.Item>
            <Descriptions.Item label="Message">
              <Paragraph>{selectedMessage.message}</Paragraph>
            </Descriptions.Item>
            <Descriptions.Item label="Received">
              {moment(selectedMessage.createdAt).format('MMMM DD, YYYY HH:mm')}
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={selectedMessage.status === 'pending' ? 'orange' : 'green'}>
                {selectedMessage.status?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* User Details Modal */}
      <Modal
        title="User Details"
        visible={userModalVisible}
        onCancel={() => setUserModalVisible(false)}
        width={700}
        footer={[
          <Button key="close" onClick={() => setUserModalVisible(false)}>
            Close
          </Button>,
          selectedUser?.isApproved !== true && (
            <Button
              key="approve"
              type="primary"
              onClick={() => updateUserStatus(selectedUser._id, true)}
            >
              Approve User
            </Button>
          ),
          selectedUser?.isApproved !== false && (
            <Button
              key="reject"
              danger
              onClick={() => updateUserStatus(selectedUser._id, false)}
            >
              Reject User
            </Button>
          )
        ]}
      >
        {selectedUser && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Name" span={2}>
              {selectedUser.firstName} {selectedUser.lastName}
            </Descriptions.Item>
            <Descriptions.Item label="Email">
              {selectedUser.email}
            </Descriptions.Item>
            <Descriptions.Item label="Role">
              <Tag color={selectedUser.role === 'teacher' ? 'blue' : 'green'}>
                {selectedUser.role?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              {selectedUser.isApproved === true ? (
                <Tag color="green" icon={<CheckCircleOutlined />}>Approved</Tag>
              ) : selectedUser.isApproved === false ? (
                <Tag color="red" icon={<CloseCircleOutlined />}>Rejected</Tag>
              ) : (
                <Tag color="orange">Pending</Tag>
              )}
            </Descriptions.Item>
            <Descriptions.Item label="Registered">
              {moment(selectedUser.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
            {selectedUser.phone && (
              <Descriptions.Item label="Phone" span={2}>
                {selectedUser.phone}
              </Descriptions.Item>
            )}
            {selectedUser.bio && (
              <Descriptions.Item label="Bio" span={2}>
                {selectedUser.bio}
              </Descriptions.Item>
            )}
          </Descriptions>
        )}
      </Modal>

      {/* Create User Modal */}
      <Modal
        title="Create New User"
        visible={createUserModalVisible}
        onCancel={() => {
          setCreateUserModalVisible(false);
          createUserForm.resetFields();
        }}
        onOk={() => createUserForm.submit()}
        width={600}
      >
        <Form
          form={createUserForm}
          layout="vertical"
          onFinish={createUser}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="firstName"
                label="First Name"
                rules={[{ required: true, message: 'Please enter first name' }]}
              >
                <Input placeholder="Enter first name" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="lastName"
                label="Last Name"
                rules={[{ required: true, message: 'Please enter last name' }]}
              >
                <Input placeholder="Enter last name" />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="email"
            label="Email"
            rules={[
              { required: true, message: 'Please enter email' },
              { type: 'email', message: 'Please enter a valid email' }
            ]}
          >
            <Input placeholder="Enter email address" />
          </Form.Item>
          
          <Form.Item
            name="password"
            label="Password"
            rules={[
              { required: true, message: 'Please enter password' },
              { min: 6, message: 'Password must be at least 6 characters' }
            ]}
          >
            <Input.Password placeholder="Enter password" />
          </Form.Item>
          
          <Form.Item
            name="role"
            label="Role"
            rules={[{ required: true, message: 'Please select a role' }]}
          >
            <Select placeholder="Select user role">
              <Option value="student">Student</Option>
              <Option value="teacher">Teacher</Option>
              <Option value="admin">Admin</Option>
            </Select>
          </Form.Item>
          
          <Form.Item
            name="phone"
            label="Phone Number"
          >
            <Input placeholder="Enter phone number (optional)" />
          </Form.Item>
          
          <Form.Item
            name="isApproved"
            label="Approval Status"
            valuePropName="checked"
          >
            <Switch checkedChildren="Approved" unCheckedChildren="Pending" />
          </Form.Item>
        </Form>
      </Modal>

      {/* Reply Modal */}
      <Modal
        title={`Reply to ${replyTarget?.name || replyTarget?.fullName || 'User'}`}
        visible={replyModalVisible}
        onCancel={() => {
          setReplyModalVisible(false);
          replyForm.resetFields();
          setReplyType('');
          setReplyTarget(null);
        }}
        onOk={() => replyForm.submit()}
        width={600}
      >
        <Form
          form={replyForm}
          layout="vertical"
          onFinish={async (values) => {
            try {
              // Prepare email data based on reply type
              const emailData = {
                to: replyTarget?.email,
                subject: values.subject,
                message: values.message,
                type: replyType,
                relatedId: replyTarget?._id
              };

              // Send email via API
              const response = await fetch(`${API_BASE_URL}/api/send-email`, {
                method: 'POST',
                headers: getAuthHeaders(),
                body: JSON.stringify(emailData)
              });

              if (response.ok) {
                message.success('Reply sent successfully!');
                
                // Update status if it's an application reply
                if (replyType === 'application' && replyTarget?.status === 'pending') {
                  await updateApplicationStatus(replyTarget._id, 'contacted');
                }
                
                // Update status if it's a message reply
                if (replyType === 'message' && replyTarget?.status === 'pending') {
                  await updateContactStatus(replyTarget._id, 'resolved');
                }
                
                setReplyModalVisible(false);
                replyForm.resetFields();
                setReplyType('');
                setReplyTarget(null);
                
                // Refresh data
                if (replyType === 'application') {
                  fetchApplications();
                } else if (replyType === 'message') {
                  fetchContactMessages();
                }
              } else {
                throw new Error('Failed to send reply');
              }
            } catch (error) {
              console.error('Error sending reply:', error);
              message.error('Failed to send reply. Please try again.');
            }
          }}
        >
          {/* Display recipient information */}
          <div style={{ 
            background: '#f0f2f5', 
            padding: '12px', 
            borderRadius: '8px',
            marginBottom: '16px' 
          }}>
            <Text strong>Replying to: </Text>
            <Text>{replyTarget?.email}</Text>
            {replyType === 'application' && (
              <>
                <br />
                <Text type="secondary">
                  Application for: {replyTarget?.course || replyTarget?.program || 'General Application'}
                </Text>
              </>
            )}
            {replyType === 'message' && replyTarget?.subject && (
              <>
                <br />
                <Text type="secondary">
                  Original Subject: {replyTarget.subject}
                </Text>
              </>
            )}
          </div>

          <Form.Item
            name="subject"
            label="Subject"
            rules={[{ required: true, message: 'Please enter subject' }]}
            initialValue={
              replyType === 'application' 
                ? `Re: Your Application to Forum Academy`
                : replyTarget?.subject 
                  ? `Re: ${replyTarget.subject}` 
                  : ''
            }
          >
            <Input placeholder="Enter email subject" />
          </Form.Item>
          
          <Form.Item
            name="message"
            label="Message"
            rules={[{ required: true, message: 'Please enter your message' }]}
          >
            <TextArea 
              rows={8} 
              placeholder={
                replyType === 'application'
                  ? "Dear Applicant,\n\nThank you for your application to Forum Academy...\n\nBest regards,\nForum Academy Team"
                  : "Type your reply message here..."
              }
            />
          </Form.Item>

          {/* Quick Templates */}
          <Form.Item label="Quick Templates">
            <Space wrap>
              {replyType === 'application' && (
                <>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.fullName || 'Applicant'},\n\nThank you for your application to Forum Academy. We have received your application and are currently reviewing it.\n\nWe will contact you within 3-5 business days with an update on your application status.\n\nIf you have any questions in the meantime, please don't hesitate to reach out.\n\nBest regards,\nForum Academy Admissions Team`
                      });
                    }}
                  >
                    Application Received
                  </Button>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.fullName || 'Applicant'},\n\nWe need additional information to process your application. Please provide:\n\n1. [Required Document/Information]\n2. [Required Document/Information]\n\nPlease reply to this email with the requested information.\n\nBest regards,\nForum Academy Admissions Team`
                      });
                    }}
                  >
                    Request Information
                  </Button>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.fullName || 'Applicant'},\n\nCongratulations! We are pleased to inform you that your application to Forum Academy has been approved.\n\nNext steps:\n1. Complete your enrollment by [date]\n2. Submit required documents\n3. Attend orientation on [date]\n\nWelcome to Forum Academy!\n\nBest regards,\nForum Academy Admissions Team`
                      });
                    }}
                  >
                    Acceptance Letter
                  </Button>
                </>
              )}
              {replyType === 'message' && (
                <>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.name || 'User'},\n\nThank you for contacting Forum Academy. We have received your message and will respond within 24-48 hours.\n\nBest regards,\nForum Academy Support Team`
                      });
                    }}
                  >
                    Acknowledgment
                  </Button>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.name || 'User'},\n\nThank you for your inquiry. [Your detailed response here]\n\nIf you have any further questions, please don't hesitate to contact us.\n\nBest regards,\nForum Academy Support Team`
                      });
                    }}
                  >
                    General Response
                  </Button>
                </>
              )}
            </Space>
          </Form.Item>
          
          <Form.Item
            name="attachments"
            label="Attachments (Optional)"
          >
            <Upload beforeUpload={() => false}>
              <Button icon={<UploadOutlined />}>Attach Files</Button>
            </Upload>
          </Form.Item>

          <Form.Item
            name="sendCopy"
            valuePropName="checked"
          >
            <Checkbox>Send me a copy of this email</Checkbox>
          </Form.Item>
        </Form>
      </Modal>

      {/* Course Modal */}
      <Modal
        title={editingCourse ? 'Edit Course' : 'Create New Course'}
        visible={courseModalVisible}
        onCancel={() => {
          setCourseModalVisible(false);
          courseForm.resetFields();
          setEditingCourse(null);
        }}
        onOk={() => courseForm.submit()}
        width={800}
      >
        <Form
          form={courseForm}
          layout="vertical"
          onFinish={handleCreateCourse}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="title"
                label="Course Title"
                rules={[{ required: true, message: 'Please enter course title' }]}
              >
                <Input placeholder="Enter course title" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="code"
                label="Course Code"
                rules={[{ required: true, message: 'Please enter course code' }]}
              >
                <Input placeholder="e.g., CS101" />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="description"
            label="Description"
            rules={[{ required: true, message: 'Please enter course description' }]}
          >
            <TextArea rows={4} placeholder="Enter course description" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="category"
                label="Category"
                rules={[{ required: true, message: 'Please select category' }]}
              >
                <Select placeholder="Select category">
                  <Option value="language">Language</Option>
                  <Option value="business">Business</Option>
                  <Option value="technology">Technology</Option>
                  <Option value="arts">Arts</Option>
                  <Option value="science">Science</Option>
                  <Option value="other">Other</Option>
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="level"
                label="Level"
                rules={[{ required: true, message: 'Please select level' }]}
              >
                <Select placeholder="Select level">
                  <Option value="beginner">Beginner</Option>
                  <Option value="intermediate">Intermediate</Option>
                  <Option value="advanced">Advanced</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="startDate"
                label="Start Date"
                rules={[{ required: true, message: 'Please select start date' }]}
              >
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="endDate"
                label="End Date"
                rules={[{ required: true, message: 'Please select end date' }]}
              >
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
            </Col>
          </Row>
          
          <Row gutter={16}>
            <Col span={8}>
              <Form.Item
                name="duration"
                label="Duration (weeks)"
                rules={[{ required: true, message: 'Please enter duration' }]}
                initialValue={12}
              >
                <InputNumber min={1} max={52} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="capacity"
                label="Maximum Students"
                rules={[{ required: true, message: 'Please enter capacity' }]}
                initialValue={30}
              >
                <InputNumber min={1} max={500} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="status"
                label="Status"
                initialValue="active"
              >
                <Select>
                  <Option value="active">Active</Option>
                  <Option value="inactive">Inactive</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>

      {/* Material Upload Modal */}
      <Modal
        title="Upload Course Material"
        visible={materialModalVisible}
        onCancel={() => {
          setMaterialModalVisible(false);
          materialForm.resetFields();
          setFileList([]);
        }}
        onOk={() => materialForm.submit()}
        width={700}
      >
        <Form
          form={materialForm}
          layout="vertical"
          onFinish={handleUploadMaterial}
        >
          <Form.Item
            name="title"
            label="Material Title"
            rules={[{ required: true, message: 'Please enter material title' }]}
          >
            <Input placeholder="Enter material title" />
          </Form.Item>
          
          <Form.Item
            name="description"
            label="Description"
          >
            <TextArea rows={3} placeholder="Enter material description (optional)" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="course"
                label="Course"
                rules={[{ required: true, message: 'Please select course' }]}
              >
                <Select placeholder="Select course">
                  {courses.map(course => (
                    <Option key={course._id} value={course._id}>
                      {course.title}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="category"
                label="Category"
                rules={[{ required: true, message: 'Please select category' }]}
              >
                <Select placeholder="Select category">
                  <Option value="lecture">Lecture</Option>
                  <Option value="assignment">Assignment</Option>
                  <Option value="resource">Resource</Option>
                  <Option value="video">Video</Option>
                  <Option value="document">Document</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            label="Upload File"
            rules={[{ required: true, message: 'Please upload a file' }]}
          >
            <Dragger
              fileList={fileList}
              beforeUpload={(file) => {
                setFileList([file]);
                return false;
              }}
              onRemove={() => setFileList([])}
              maxCount={1}
            >
              <p className="ant-upload-drag-icon">
                <InboxOutlined />
              </p>
              <p className="ant-upload-text">Click or drag file to this area to upload</p>
              <p className="ant-upload-hint">
                Support for PDF, DOC, DOCX, PPT, PPTX, XLS, XLSX, ZIP, RAR
              </p>
            </Dragger>
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="week"
                label="Week Number"
              >
                <InputNumber min={1} max={52} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="accessLevel"
                label="Access Level"
              >
                <Select defaultValue="course_students">
                  <Option value="public">Public</Option>
                  <Option value="course_students">Course Students Only</Option>
                  <Option value="premium">Premium Members</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>

      {/* Quiz Modal */}
      <Modal
        title={editingQuiz ? 'Edit Quiz' : 'Create New Quiz'}
        visible={quizModalVisible}
        onCancel={() => {
          setQuizModalVisible(false);
          quizForm.resetFields();
          setEditingQuiz(null);
          setQuestions([]);
        }}
        footer={null}
        width={900}
      >
        <Form
          form={quizForm}
          layout="vertical"
          onFinish={handleCreateQuiz}
        >
          <Tabs defaultActiveKey="basic">
            <TabPane tab="Basic Information" key="basic">
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="title"
                    label="Quiz Title"
                    rules={[{ required: true, message: 'Please enter quiz title' }]}
                  >
                    <Input placeholder="Enter quiz title" />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="course"
                    label="Course"
                    rules={[{ required: true, message: 'Please select course' }]}
                  >
                    <Select placeholder="Select course">
                      {courses.map(course => (
                        <Option key={course._id} value={course._id}>
                          {course.title}
                        </Option>
                      ))}
                    </Select>
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="description"
                label="Description"
              >
                <TextArea rows={3} placeholder="Enter quiz description" />
              </Form.Item>
              
              <Row gutter={16}>
                <Col span={8}>
                  <Form.Item
                    name="duration"
                    label="Duration (minutes)"
                    rules={[{ required: true, message: 'Please enter duration' }]}
                  >
                    <InputNumber min={1} max={300} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="passingScore"
                    label="Passing Score (%)"
                    rules={[{ required: true, message: 'Please enter passing score' }]}
                  >
                    <InputNumber min={0} max={100} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="attempts"
                    label="Max Attempts"
                  >
                    <InputNumber min={1} max={10} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
              
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="availableFrom"
                    label="Available From"
                  >
                    <DatePicker showTime style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="availableTo"
                    label="Available Until"
                  >
                    <DatePicker showTime style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
            </TabPane>
            
            <TabPane tab={`Questions (${questions.length})`} key="questions">
              <Button
                type="dashed"
                icon={<PlusOutlined />}
                onClick={() => setQuestionsModalVisible(true)}
                style={{ width: '100%', marginBottom: 16 }}
              >
                Add Question
              </Button>
              
              {questions.length > 0 ? (
                <List
                  dataSource={questions}
                  renderItem={(question, index) => (
                    <List.Item
                      actions={[
                        <Button
                          icon={<EditOutlined />}
                          size="small"
                          onClick={() => message.info('Edit functionality coming soon')}
                        />,
                        <Button
                          icon={<DeleteOutlined />}
                          size="small"
                          danger
                          onClick={() => removeQuestion(question.id)}
                        />
                      ]}
                    >
                      <List.Item.Meta
                        avatar={<Avatar>{index + 1}</Avatar>}
                        title={question.question}
                        description={
                          <div>
                            <Tag color="blue">{question.type}</Tag>
                            <Tag color="green">Points: {question.points || 1}</Tag>
                            {question.type === 'multiple_choice' && (
                              <div style={{ marginTop: 8 }}>
                                Options: {question.options?.join(', ')}
                              </div>
                            )}
                          </div>
                        }
                      />
                    </List.Item>
                  )}
                />
              ) : (
                <Empty description="No questions added yet" />
              )}
            </TabPane>
          </Tabs>
          
          <div style={{ marginTop: 24, textAlign: 'right' }}>
            <Space>
              <Button onClick={() => {
                setQuizModalVisible(false);
                quizForm.resetFields();
                setQuestions([]);
              }}>
                Cancel
              </Button>
              <Button type="primary" htmlType="submit">
                {editingQuiz ? 'Update Quiz' : 'Create Quiz'}
              </Button>
            </Space>
          </div>
        </Form>
      </Modal>

      {/* Add Question Modal */}
      <Modal
        title="Add Question"
        visible={questionsModalVisible}
        onCancel={() => {
          setQuestionsModalVisible(false);
          questionForm.resetFields();
        }}
        onOk={() => {
          addQuestion();
          setQuestionsModalVisible(false);
        }}
        width={600}
      >
        <Form
          form={questionForm}
          layout="vertical"
        >
          <Form.Item
            name="question"
            label="Question"
            rules={[{ required: true, message: 'Please enter question' }]}
          >
            <TextArea rows={3} placeholder="Enter your question" />
          </Form.Item>
          
          <Form.Item
            name="type"
            label="Question Type"
            rules={[{ required: true, message: 'Please select question type' }]}
          >
            <Select placeholder="Select question type">
              <Option value="multiple_choice">Multiple Choice</Option>
              <Option value="true_false">True/False</Option>
              <Option value="short_answer">Short Answer</Option>
              <Option value="essay">Essay</Option>
            </Select>
          </Form.Item>
          
          <Form.Item
            noStyle
            shouldUpdate={(prevValues, currentValues) => 
              prevValues.type !== currentValues.type
            }
          >
            {({ getFieldValue }) =>
              getFieldValue('type') === 'multiple_choice' ? (
                <Form.Item
                  name="options"
                  label="Options"
                  rules={[{ required: true, message: 'Please add options' }]}
                >
                  <Select
                    mode="tags"
                    placeholder="Add options (press Enter after each)"
                    style={{ width: '100%' }}
                  />
                </Form.Item>
              ) : null
            }
          </Form.Item>
          
          <Form.Item
            name="correctAnswer"
            label="Correct Answer"
            rules={[{ required: true, message: 'Please enter correct answer' }]}
          >
            <Input placeholder="Enter the correct answer" />
          </Form.Item>
          
          <Form.Item
            name="points"
            label="Points"
          >
            <InputNumber min={1} max={100} defaultValue={1} />
          </Form.Item>
        </Form>
      </Modal>

      {/* Homework Modal */}
      <Modal
        title={editingHomework ? 'Edit Homework' : 'Create New Homework'}
        visible={homeworkModalVisible}
        onCancel={() => {
          setHomeworkModalVisible(false);
          homeworkForm.resetFields();
          setEditingHomework(null);
        }}
        onOk={() => homeworkForm.submit()}
        width={800}
      >
        <Form
          form={homeworkForm}
          layout="vertical"
          onFinish={handleCreateHomework}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="title"
                label="Assignment Title"
                rules={[{ required: true, message: 'Please enter assignment title' }]}
              >
                <Input placeholder="Enter assignment title" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="course"
                label="Course"
                rules={[{ required: true, message: 'Please select course' }]}
              >
                <Select placeholder="Select course">
                  {courses.map(course => (
                    <Option key={course._id} value={course._id}>
                      {course.title}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="description"
            label="Description"
            rules={[{ required: true, message: 'Please enter assignment description' }]}
          >
            <TextArea rows={4} placeholder="Enter assignment description" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="dueDate"
                label="Due Date"
                rules={[{ required: true, message: 'Please select due date' }]}
              >
                <DatePicker showTime style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="totalPoints"
                label="Total Points"
                rules={[{ required: true, message: 'Please enter total points' }]}
              >
                <InputNumber min={1} max={1000} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="instructions"
            label="Instructions"
          >
            <TextArea rows={3} placeholder="Enter detailed instructions for students" />
          </Form.Item>
        </Form>
      </Modal>

      {/* Exercise Modal */}
      <Modal
        title={editingExercise ? 'Edit Exercise' : 'Create New Listening Exercise'}
        visible={exerciseModalVisible}
        onCancel={() => {
          setExerciseModalVisible(false);
          exerciseForm.resetFields();
          setEditingExercise(null);
          setAudioFile(null);
          setFileList([]);
          setQuestions([]);
        }}
        footer={null}
        width={900}
      >
        <Form
          form={exerciseForm}
          layout="vertical"
          onFinish={handleCreateExercise}
        >
          <Tabs defaultActiveKey="basic">
            <TabPane tab="Basic Information" key="basic">
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="title"
                    label="Exercise Title"
                    rules={[{ required: true, message: 'Please enter exercise title' }]}
                  >
                    <Input placeholder="Enter exercise title" />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="course"
                    label="Course"
                    rules={[{ required: true, message: 'Please select course' }]}
                  >
                    <Select placeholder="Select course">
                      {courses.map(course => (
                        <Option key={course._id} value={course._id}>
                          {course.title}
                        </Option>
                      ))}
                    </Select>
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="description"
                label="Description"
              >
                <TextArea rows={3} placeholder="Enter exercise description" />
              </Form.Item>
              
              <Row gutter={16}>
                <Col span={8}>
                  <Form.Item
                    name="level"
                    label="Difficulty Level"
                    rules={[{ required: true, message: 'Please select level' }]}
                  >
                    <Select placeholder="Select level">
                      <Option value="beginner">Beginner</Option>
                      <Option value="intermediate">Intermediate</Option>
                      <Option value="advanced">Advanced</Option>
                    </Select>
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="timeLimit"
                    label="Time Limit (minutes)"
                  >
                    <InputNumber min={1} max={120} defaultValue={30} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="playLimit"
                    label="Play Limit"
                  >
                    <InputNumber min={1} max={10} defaultValue={3} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="instructions"
                label="Instructions"
              >
                <TextArea rows={3} placeholder="Enter instructions for students" />
              </Form.Item>
              
              <Form.Item
                label="Audio File (MP3/WAV)"
                required={!editingExercise}
              >
                <Upload
                  beforeUpload={(file) => {
                    // Validate file type
                    const allowedTypes = ['audio/mp3', 'audio/mpeg', 'audio/wav', 'audio/x-wav'];
                    const isValidType = allowedTypes.includes(file.type) || 
                                       file.name.toLowerCase().endsWith('.mp3') || 
                                       file.name.toLowerCase().endsWith('.wav');
                    
                    if (!isValidType) {
                      message.error('Please upload a valid MP3 or WAV audio file');
                      return Upload.LIST_IGNORE;
                    }
                    
                    // Check file size (50MB limit)
                    const isLessThan50M = file.size / 1024 / 1024 < 50;
                    if (!isLessThan50M) {
                      message.error('Audio file must be smaller than 50MB!');
                      return Upload.LIST_IGNORE;
                    }
                    
                    setAudioFile(file);
                    setFileList([file]);
                    
                    // Create a preview URL for the uploaded file
                    const url = URL.createObjectURL(file);
                    console.log('Audio file selected:', file.name, 'Type:', file.type, 'Size:', (file.size / 1024 / 1024).toFixed(2) + 'MB');
                    
                    return false; // Prevent automatic upload
                  }}
                  onRemove={() => {
                    setAudioFile(null);
                    setFileList([]);
                  }}
                  fileList={fileList}
                  accept=".mp3,.wav,audio/mp3,audio/mpeg,audio/wav"
                  maxCount={1}
                  showUploadList={{
                    showPreviewIcon: true,
                    showRemoveIcon: true,
                    showDownloadIcon: false,
                  }}
                >
                  <Button icon={<UploadOutlined />} disabled={fileList.length >= 1}>
                    {fileList.length >= 1 ? 'Audio File Selected' : 'Select MP3/WAV File'}
                  </Button>
                </Upload>
                {audioFile && (
                  <div style={{ marginTop: 8 }}>
                    <Text type="secondary">
                      Selected: {audioFile.name} ({(audioFile.size / 1024 / 1024).toFixed(2)} MB)
                    </Text>
                  </div>
                )}
                {editingExercise?.audioUrl && !audioFile && (
                  <div style={{ marginTop: 8 }}>
                    <Text type="success">Current audio file: {editingExercise.originalFileName || 'audio.mp3'}</Text>
                    <br />
                    <Text type="secondary">Upload a new file to replace the current one</Text>
                  </div>
                )}
              </Form.Item>
              
              <Form.Item
                name="transcript"
                label="Transcript (Optional)"
              >
                <TextArea rows={4} placeholder="Enter audio transcript" />
              </Form.Item>
            </TabPane>
            
            <TabPane tab={`Questions (${questions.length})`} key="questions">
              <Button
                type="dashed"
                icon={<PlusOutlined />}
                onClick={() => setQuestionsModalVisible(true)}
                style={{ width: '100%', marginBottom: 16 }}
              >
                Add Question
              </Button>
              
              {questions.length > 0 ? (
                <List
                  dataSource={questions}
                  renderItem={(question, index) => (
                    <List.Item
                      actions={[
                        <Button
                          icon={<DeleteOutlined />}
                          size="small"
                          danger
                          onClick={() => removeQuestion(question.id)}
                        />
                      ]}
                    >
                      <List.Item.Meta
                        avatar={<Avatar>{index + 1}</Avatar>}
                        title={question.question}
                        description={
                          <div>
                            <Tag color="blue">{question.type}</Tag>
                            <Tag color="green">Points: {question.points || 1}</Tag>
                          </div>
                        }
                      />
                    </List.Item>
                  )}
                />
              ) : (
                <Empty description="No questions added yet" />
              )}
            </TabPane>
          </Tabs>
          
          <div style={{ marginTop: 24, textAlign: 'right' }}>
            <Space>
              <Button onClick={() => {
                setExerciseModalVisible(false);
                exerciseForm.resetFields();
                setQuestions([]);
                setAudioFile(null);
                setFileList([]);
                setEditingExercise(null);
              }}>
                Cancel
              </Button>
              <Button type="primary" htmlType="submit">
                {editingExercise ? 'Update Exercise' : 'Create Exercise'}
              </Button>
            </Space>
          </div>
        </Form>
      </Modal>

      {/* Submissions Modal */}
      <Modal
        title="View Submissions"
        visible={submissionsModalVisible}
        onCancel={() => setSubmissionsModalVisible(false)}
        width={1000}
        footer={[
          <Button key="close" onClick={() => setSubmissionsModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        <Table
          columns={[
            {
              title: 'Student',
              key: 'student',
              render: (_, record) => (
                <div>
                  <Text strong>{record.studentName || 'Unknown Student'}</Text>
                  <br />
                  <Text type="secondary" style={{ fontSize: '12px' }}>
                    {record.studentEmail || 'No email'}
                  </Text>
                </div>
              )
            },
            {
              title: 'Score',
              dataIndex: 'score',
              key: 'score',
              render: (score, record) => {
                const percentage = record.totalPoints ? Math.round((score / record.totalPoints) * 100) : 0;
                return (
                  <div>
                    <Text strong>{score || 0}/{record.totalPoints || 0}</Text>
                    <br />
                    <Progress
                      percent={percentage}
                      size="small"
                      strokeColor={percentage >= 70 ? '#52c41a' : percentage >= 40 ? '#faad14' : '#f5222d'}
                    />
                  </div>
                );
              }
            },
            {
              title: 'Submitted',
              dataIndex: 'submittedAt',
              key: 'submittedAt',
              render: (date) => moment(date).format('MMM DD, YYYY HH:mm')
            },
            {
              title: 'Status',
              dataIndex: 'status',
              key: 'status',
              render: (status) => (
                <Tag color={status === 'graded' ? 'green' : 'orange'}>
                  {status?.toUpperCase() || 'PENDING'}
                </Tag>
              )
            },
            {
              title: 'Actions',
              key: 'actions',
              render: (_, record) => (
                <Space>
                  <Button
                    icon={<EyeOutlined />}
                    size="small"
                    onClick={() => {
                      setSelectedSubmission(record);
                      setViewModalVisible(true);
                    }}
                  >
                    View
                  </Button>
                  <Button
                    icon={<EditOutlined />}
                    size="small"
                    onClick={() => {
                      setSelectedSubmission(record);
                      setGradingModalVisible(true);
                    }}
                  >
                    Grade
                  </Button>
                </Space>
              )
            }
          ]}
          dataSource={submissions}
          rowKey="_id"
          pagination={{
            pageSize: 10,
            showSizeChanger: true
          }}
        />
      </Modal>

      {/* Progress Modal */}
      <Modal
        title="Student Progress Details"
        visible={progressModalVisible}
        onCancel={() => setProgressModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setProgressModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        {selectedProgress && (
          <div>
            <Descriptions bordered column={2} style={{ marginBottom: 24 }}>
              <Descriptions.Item label="Student Name" span={2}>
                {selectedProgress.firstName} {selectedProgress.lastName}
              </Descriptions.Item>
              <Descriptions.Item label="Email">
                {selectedProgress.email}
              </Descriptions.Item>
              <Descriptions.Item label="Registration Date">
                {moment(selectedProgress.createdAt).format('MMMM DD, YYYY')}
              </Descriptions.Item>
            </Descriptions>
            
            <Card title="Course Progress" style={{ marginBottom: 16 }}>
              <Row gutter={[16, 16]}>
                <Col span={8}>
                  <Statistic
                    title="Courses Enrolled"
                    value={Math.floor(Math.random() * 5) + 1}
                    prefix={<BookOutlined />}
                  />
                </Col>
                <Col span={8}>
                  <Statistic
                    title="Avg. Progress"
                    value={Math.floor(Math.random() * 100)}
                    suffix="%"
                    prefix={<TrophyOutlined />}
                  />
                </Col>
                <Col span={8}>
                  <Statistic
                    title="Assignments Completed"
                    value={Math.floor(Math.random() * 20)}
                    prefix={<CheckSquareOutlined />}
                  />
                </Col>
              </Row>
            </Card>
            
            <Card title="Recent Activity">
              <Timeline>
                <Timeline.Item color="green">
                  <Text>Completed Quiz: JavaScript Basics</Text>
                  <br />
                  <Text type="secondary">2 days ago</Text>
                </Timeline.Item>
                <Timeline.Item color="blue">
                  <Text>Submitted Homework: React Components</Text>
                  <br />
                  <Text type="secondary">5 days ago</Text>
                </Timeline.Item>
                <Timeline.Item color="orange">
                  <Text>Downloaded Material: CSS Grid Guide</Text>
                  <br />
                  <Text type="secondary">1 week ago</Text>
                </Timeline.Item>
              </Timeline>
            </Card>
          </div>
        )}
      </Modal>

      {/* Preview Modal */}
      <Modal
        title="Material Preview"
        visible={previewModalVisible}
        onCancel={() => setPreviewModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setPreviewModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="download"
            type="primary"
            icon={<DownloadOutlined />}
            onClick={() => {
              if (selectedMaterial) {
                window.open(`${API_BASE_URL}/uploads/${selectedMaterial.filePath}`, '_blank');
              }
            }}
          >
            Download
          </Button>
        ]}
      >
        {selectedMaterial && (
          <div>
            <Descriptions bordered column={2} style={{ marginBottom: 24 }}>
              <Descriptions.Item label="Title" span={2}>
                {selectedMaterial.title}
              </Descriptions.Item>
              <Descriptions.Item label="Description" span={2}>
                {selectedMaterial.description || 'No description'}
              </Descriptions.Item>
              <Descriptions.Item label="Category">
                {selectedMaterial.category}
              </Descriptions.Item>
              <Descriptions.Item label="File Size">
                {((selectedMaterial.fileSize || 0) / (1024 * 1024)).toFixed(2)} MB
              </Descriptions.Item>
              <Descriptions.Item label="Uploaded">
                {moment(selectedMaterial.createdAt).format('MMMM DD, YYYY')}
              </Descriptions.Item>
              <Descriptions.Item label="Access Level">
                {selectedMaterial.accessLevel || 'course_students'}
              </Descriptions.Item>
            </Descriptions>
            
            <Card title="File Preview">
              <div style={{ textAlign: 'center', padding: '40px' }}>
                {selectedMaterial.fileType === 'pdf' ? (
                  <div>
                    <FileTextOutlined style={{ fontSize: 64, color: '#1890ff' }} />
                    <br />
                    <Text>PDF Document</Text>
                  </div>
                ) : selectedMaterial.fileType === 'video' ? (
                  <div>
                    <VideoCameraOutlined style={{ fontSize: 64, color: '#52c41a' }} />
                    <br />
                    <Text>Video File</Text>
                  </div>
                ) : (
                  <div>
                    <FileOutlined style={{ fontSize: 64, color: '#faad14' }} />
                    <br />
                    <Text>Document File</Text>
                  </div>
                )}
              </div>
            </Card>
          </div>
        )}
      </Modal>

      {/* Results Modal */}
      <Modal
        title="Quiz Results & Analytics"
        visible={resultsModalVisible}
        onCancel={() => setResultsModalVisible(false)}
        width={1000}
        footer={[
          <Button key="close" onClick={() => setResultsModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        {selectedQuiz && (
          <div>
            <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Total Submissions"
                    value={selectedQuiz.submissions?.length || 0}
                    prefix={<FormOutlined />}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Average Score"
                    value={78}
                    suffix="%"
                    prefix={<TrophyOutlined />}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Pass Rate"
                    value={85}
                    suffix="%"
                    prefix={<CheckCircleOutlined />}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Completion Rate"
                    value={92}
                    suffix="%"
                    prefix={<ClockCircleOutlined />}
                  />
                </Card>
              </Col>
            </Row>
            
            <Row gutter={[16, 16]}>
              <Col span={12}>
                <Card title="Score Distribution">
                  <Bar
                    data={{
                      labels: ['0-40%', '41-60%', '61-80%', '81-100%'],
                      datasets: [{
                        label: 'Number of Students',
                        data: [2, 5, 8, 12],
                        backgroundColor: [
                          '#f5222d',
                          '#faad14',
                          '#1890ff',
                          '#52c41a'
                        ]
                      }]
                    }}
                    options={{
                      responsive: true,
                      plugins: {
                        legend: {
                          display: false
                        }
                      }
                    }}
                  />
                </Card>
              </Col>
              <Col span={12}>
                <Card title="Question Analysis">
                  <List
                    dataSource={selectedQuiz.questions?.slice(0, 5) || []}
                    renderItem={(question, index) => (
                      <List.Item>
                        <List.Item.Meta
                          avatar={<Avatar>{index + 1}</Avatar>}
                          title={`Question ${index + 1}`}
                          description={
                            <div>
                              <Progress
                                percent={Math.floor(Math.random() * 100)}
                                size="small"
                                format={(percent) => `${percent}% correct`}
                              />
                            </div>
                          }
                        />
                      </List.Item>
                    )}
                  />
                </Card>
              </Col>
            </Row>
          </div>
        )}
      </Modal>

      {/* Grading Modal */}
      <Modal
        title="Grade Submission"
        visible={gradingModalVisible}
        onCancel={() => setGradingModalVisible(false)}
        onOk={() => gradingForm.submit()}
        width={700}
      >
        <Form
          form={gradingForm}
          layout="vertical"
          onFinish={(values) => {
            message.success('Grade submitted successfully!');
            setGradingModalVisible(false);
            gradingForm.resetFields();
          }}
        >
          {selectedSubmission && (
            <div>
              <Descriptions bordered column={2} style={{ marginBottom: 24 }}>
                <Descriptions.Item label="Student">
                  {selectedSubmission.studentName || 'Unknown Student'}
                </Descriptions.Item>
                <Descriptions.Item label="Assignment">
                  {selectedHomework?.title || selectedQuiz?.title || 'Unknown'}
                </Descriptions.Item>
                <Descriptions.Item label="Submitted">
                  {moment(selectedSubmission.submittedAt).format('MMMM DD, YYYY HH:mm')}
                </Descriptions.Item>
                <Descriptions.Item label="Current Score">
                  {selectedSubmission.score || 0}/{selectedSubmission.totalPoints || 0}
                </Descriptions.Item>
              </Descriptions>
              
              <Form.Item
                name="score"
                label="Score"
                rules={[{ required: true, message: 'Please enter score' }]}
              >
                <InputNumber
                  min={0}
                  max={selectedSubmission.totalPoints || 100}
                  style={{ width: '100%' }}
                  placeholder="Enter score"
                />
              </Form.Item>
              
              <Form.Item
                name="feedback"
                label="Feedback"
              >
                <TextArea
                  rows={4}
                  placeholder="Enter feedback for the student"
                />
              </Form.Item>
              
              <Form.Item
                name="status"
                label="Status"
              >
                <Select defaultValue="graded">
                  <Option value="graded">Graded</Option>
                  <Option value="needs_revision">Needs Revision</Option>
                  <Option value="excellent">Excellent</Option>
                </Select>
              </Form.Item>
            </div>
          )}
        </Form>
      </Modal>

      {/* View Submission Modal */}
      <Modal
        title="Submission Details"
        visible={viewModalVisible}
        onCancel={() => setViewModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setViewModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        {selectedSubmission && (
          <div>
            <Descriptions bordered column={2}>
              <Descriptions.Item label="Student" span={2}>
                {selectedSubmission.studentName || 'Unknown Student'}
              </Descriptions.Item>
              <Descriptions.Item label="Assignment">
                {selectedHomework?.title || selectedQuiz?.title || 'Unknown'}
              </Descriptions.Item>
              <Descriptions.Item label="Score">
                {selectedSubmission.score || 0}/{selectedSubmission.totalPoints || 0}
              </Descriptions.Item>
              <Descriptions.Item label="Submitted">
                {moment(selectedSubmission.submittedAt).format('MMMM DD, YYYY HH:mm')}
              </Descriptions.Item>
              <Descriptions.Item label="Status">
                <Tag color={selectedSubmission.status === 'graded' ? 'green' : 'orange'}>
                  {selectedSubmission.status?.toUpperCase() || 'PENDING'}
                </Tag>
              </Descriptions.Item>
              <Descriptions.Item label="Feedback" span={2}>
                {selectedSubmission.feedback || 'No feedback provided'}
              </Descriptions.Item>
            </Descriptions>
            
            {selectedSubmission.answers && (
              <Card title="Student Answers" style={{ marginTop: 16 }}>
                <List
                  dataSource={selectedSubmission.answers}
                  renderItem={(answer, index) => (
                    <List.Item>
                      <List.Item.Meta
                        avatar={<Avatar>{index + 1}</Avatar>}
                        title={`Question ${index + 1}`}
                        description={
                          <div>
                            <Text strong>Answer: </Text>
                            <Text>{answer.answer || 'No answer provided'}</Text>
                            <br />
                            <Text strong>Correct: </Text>
                            <Tag color={answer.isCorrect ? 'green' : 'red'}>
                              {answer.isCorrect ? 'Yes' : 'No'}
                            </Tag>
                          </div>
                        }
                      />
                    </List.Item>
                  )}
                />
              </Card>
            )}
          </div>
        )}
      </Modal>
    </Layout>
  );
};

export default AdminFacultyDashboard;
